"use client";

import { useEffect, useState, useCallback, useRef } from "react";
import Link from "next/link";

import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { useDelayedLoading } from "@/hooks/use-delayed-loading";
import { cn } from "@/lib/utils";
import { apiGet } from "@/lib/api";

/* -- types --------------------------------------------------------- */

interface Repository {
  id: string;
  installationId: string;
  githubId: string;
  fullName: string;
  name: string;
  owner: string;
  visibility: string;
  defaultBranch: string;
  archived: boolean;
  language: string | null;
  syncedAt: string | null;
  createdAt: string;
  updatedAt: string;
}

/* -- helpers ------------------------------------------------------- */

const visibilityBadge: Record<string, { label: string; variant: "default" | "warning" | "secondary" }> = {
  public: { label: "public", variant: "default" },
  private: { label: "private", variant: "warning" },
  internal: { label: "internal", variant: "secondary" },
};

function formatDate(iso: string | null): string {
  if (!iso) return "never";
  const d = new Date(iso);
  const now = new Date();
  const diffMs = now.getTime() - d.getTime();
  const diffMins = Math.floor(diffMs / 60_000);
  if (diffMins < 1) return "just now";
  if (diffMins < 60) return `${diffMins}m ago`;
  const diffHours = Math.floor(diffMins / 60);
  if (diffHours < 24) return `${diffHours}h ago`;
  const diffDays = Math.floor(diffHours / 24);
  if (diffDays < 7) return `${diffDays}d ago`;
  return d.toLocaleDateString();
}

/* -- page ---------------------------------------------------------- */

export default function GitHubRepositoriesPage() {
  const [repos, setRepos] = useState<Repository[]>([]);
  const [loading, setLoading] = useState(true);
  const showLoading = useDelayedLoading(loading);
  const [error, setError] = useState<string | null>(null);

  // Filters
  const [visibilityFilter, setVisibilityFilter] = useState<string>("all");
  const [searchQuery, setSearchQuery] = useState("");
  const [debouncedSearch, setDebouncedSearch] = useState("");
  const searchInputRef = useRef<HTMLInputElement>(null);

  // Debounce search
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSearch(searchQuery);
    }, 300);
    return () => clearTimeout(timer);
  }, [searchQuery]);

  const fetchRepos = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const res = await apiGet<{ data: Repository[] }>("/modules/github/repositories");
      setRepos(res.data);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to load repositories");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchRepos();
  }, [fetchRepos]);

  // Client-side filtering
  const filteredRepos = repos.filter((repo) => {
    if (visibilityFilter !== "all" && repo.visibility !== visibilityFilter) return false;
    if (debouncedSearch && !repo.fullName.toLowerCase().includes(debouncedSearch.toLowerCase())) return false;
    return true;
  });

  const hasActiveFilters = visibilityFilter !== "all" || debouncedSearch !== "";

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-lg text-primary text-glow">
            $ github repos ls
            {hasActiveFilters && (
              <span className="text-muted-foreground"> --filter</span>
            )}
            <span className="ml-1 animate-pulse">_</span>
          </h1>
          <p className="mt-1 text-xs text-muted-foreground">
            {">"} tracked github repositories
          </p>
        </div>
        <Link
          href="/github"
          className="text-xs text-muted-foreground hover:text-primary transition-colors"
        >
          [back]
        </Link>
      </div>

      {/* Search */}
      <div className="flex items-center gap-2 rounded-md border border-border bg-background px-3 py-2 text-sm transition-colors focus-within:border-primary">
        <span className="text-muted-foreground shrink-0">{">"}</span>
        <input
          ref={searchInputRef}
          type="text"
          className="w-full bg-transparent outline-none placeholder:text-muted-foreground font-mono"
          placeholder="search repositories by name..."
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
        />
        {searchQuery && (
          <button
            onClick={() => setSearchQuery("")}
            className="shrink-0 text-muted-foreground hover:text-foreground transition-colors text-xs"
          >
            [x]
          </button>
        )}
      </div>

      {/* Filters */}
      <div className="space-y-1.5 text-xs">
        <div className="flex items-center gap-3">
          <span className="text-muted-foreground w-24">--visibility</span>
          {["all", "public", "private", "internal"].map((v) => (
            <button
              key={v}
              onClick={() => setVisibilityFilter(v)}
              className={cn(
                "transition-colors",
                visibilityFilter === v
                  ? "text-foreground"
                  : "text-muted-foreground/60 hover:text-foreground",
              )}
            >
              {visibilityFilter === v ? `[${v}]` : v}
            </button>
          ))}
          {hasActiveFilters && (
            <button
              onClick={() => {
                setVisibilityFilter("all");
                setSearchQuery("");
              }}
              className="text-xs text-muted-foreground hover:text-destructive transition-colors ml-1"
            >
              [clear]
            </button>
          )}
        </div>
      </div>

      {/* Content */}
      <div className="min-h-[300px]">
        {showLoading || loading ? (
          <div className={showLoading ? "space-y-1" : "space-y-1 invisible"}>
            {[...Array(5)].map((_, i) => (
              <div key={i} className="flex items-center gap-x-3 px-3 py-2">
                <div className="h-3 w-48 animate-pulse rounded bg-muted" />
                <div className="h-3 w-16 animate-pulse rounded bg-muted" />
                <div className="h-3 w-20 animate-pulse rounded bg-muted" />
                <div className="h-3 w-24 animate-pulse rounded bg-muted" />
              </div>
            ))}
          </div>
        ) : error ? (
          <Card>
            <CardContent className="flex flex-col items-center justify-center py-12">
              <p className="text-sm text-destructive">[ERR] {error}</p>
              <Button variant="outline" size="sm" className="mt-4" onClick={fetchRepos}>
                $ retry
              </Button>
            </CardContent>
          </Card>
        ) : filteredRepos.length === 0 ? (
          <Card>
            <CardContent className="flex flex-col items-center justify-center py-16">
              <p className="text-sm text-muted-foreground">
                {">"} no repositories found
              </p>
              <p className="mt-1 text-xs text-muted-foreground">
                {hasActiveFilters
                  ? "try adjusting or clearing your filters"
                  : repos.length === 0
                    ? "sync your installations to populate repositories"
                    : "no repositories match your criteria"}
              </p>
            </CardContent>
          </Card>
        ) : (
          <div className="overflow-x-auto animate-content-ready">
            <div className="min-w-[700px]">
              {/* Header */}
              <div className="grid grid-cols-[minmax(200px,2fr)_80px_70px_100px_100px] gap-x-3 border-b border-border px-3 py-2 text-xs font-medium uppercase tracking-wider text-muted-foreground">
                <span>Repository</span>
                <span>Visibility</span>
                <span>Status</span>
                <span>Branch</span>
                <span className="text-right">Last Synced</span>
              </div>

              <p className="px-3 pt-2 text-xs text-muted-foreground">
                {filteredRepos.length} repositor{filteredRepos.length !== 1 ? "ies" : "y"}
                {filteredRepos.length !== repos.length && ` of ${repos.length} total`}
              </p>

              {/* Rows */}
              {filteredRepos.map((repo) => {
                const vis = visibilityBadge[repo.visibility] ?? {
                  label: repo.visibility,
                  variant: "secondary" as const,
                };

                return (
                  <div
                    key={repo.id}
                    className="group grid grid-cols-[minmax(200px,2fr)_80px_70px_100px_100px] items-center gap-x-3 border border-transparent px-3 py-2 text-sm transition-colors hover:border-border hover:bg-muted/30"
                  >
                    <span className="truncate text-foreground group-hover:text-primary font-medium font-mono transition-colors">
                      {repo.fullName}
                    </span>

                    <Badge variant={vis.variant}>
                      [{vis.label}]
                    </Badge>

                    <span
                      className={cn(
                        "font-mono text-xs",
                        repo.archived ? "text-muted-foreground" : "text-primary",
                      )}
                    >
                      {repo.archived ? "[archived]" : "[active]"}
                    </span>

                    <span className="text-xs text-muted-foreground font-mono">
                      {repo.defaultBranch}
                    </span>

                    <span className="text-xs text-muted-foreground text-right">
                      {formatDate(repo.syncedAt)}
                    </span>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
